"use client";
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { APIProvider, Map, Marker } from '@vis.gl/react-google-maps';

export default function TherapistConnect() {
    const router = useRouter();
    const [pendingRequests, setPendingRequests] = useState([]);
    const [approvedMatches, setApprovedMatches] = useState([]);
    const [balance, setBalance] = useState(0);
    const [loading, setLoading] = useState(true);
    
    // モーダル・デモ状態管理
    const [showSoapModal, setShowSoapModal] = useState(false);
    const [showSnsModal, setShowSnsModal] = useState(false);
    const [showChart, setShowChart] = useState(false);
    const [isAiAnalyzing, setIsAiAnalyzing] = useState(false);

    const [soapForm, setSoapForm] = useState({ s: "", o: "", a: "", p: "" });

    // APIキーと位置データ
    const API_KEY = "YOUR_API_KEY_HERE"; 
    const HAKATA_STATION = { lat: 33.5897, lng: 130.4207 };
    const userLocations = [{ id: 1, position: { lat: 33.592, lng: 130.415 } }, { id: 2, position: { lat: 33.585, lng: 130.425 } }];

    const chatHistory = [
        { sender: "利用者", text: "最近、階段の上り下りがスムーズになってきました！" },
        { sender: "利用者", text: "膝の痛みはほとんど感じません。" }
    ];

    useEffect(() => {
        const fetchData = async () => {
            try {
                const [reqRes, chatRes] = await Promise.all([fetch("/api/users"), fetch("/api/chats/list")]);
                const userData = await reqRes.json();
                const approvedData = await chatRes.json();
                setPendingRequests(userData.filter((u: any) => !u.isApproved)); 
                setApprovedMatches(approvedData);
                setBalance(userData.filter((u: any) => u.isApproved).length * 5000);
                setLoading(false);
            } catch (err) {
                console.error("データ取得エラー", err);
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    const runAiAnalysis = () => {
        setIsAiAnalyzing(true);
        setTimeout(() => {
            setSoapForm({
                s: "「階段昇降がスムーズ」「膝痛消失」",
                o: "10m歩行: 8.5秒(前回10.2秒)",
                a: "下肢筋力向上により立脚相が安定。",
                p: "歩行距離の延長を試みる。"
            });
            setIsAiAnalyzing(false);
        }, 1200);
    };

    if (loading) return <div style={{ textAlign: "center", padding: "100px", color: "#666" }}>データを同期中...</div>;

    return (
        <APIProvider apiKey={API_KEY}>
            <div style={{ padding: "40px", maxWidth: "1100px", margin: "0 auto", fontFamily: 'sans-serif', backgroundColor: "#fcfcfc", minHeight: "100vh" }}>
                
                {/* 報酬 & KPI */}
                <div style={{ display: "grid", gridTemplateColumns: "2fr 1fr", gap: "20px", marginBottom: "30px" }}>
                    <div style={{ border: "1px solid #0070f3", padding: "25px", borderRadius: "20px", backgroundColor: "#f0f7ff", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                        <div>
                            <p style={{ margin: 0, color: "#0070f3", fontSize: "12px", fontWeight: "bold" }}>TOTAL REVENUE</p>
                            <h2 style={{ fontSize: "42px", margin: "5px 0", color: "#1a1a1a", fontWeight: "900" }}>¥{balance.toLocaleString()}</h2>
                        </div>
                        <div style={{ textAlign: "right" }}>
                            <div style={{ fontSize: "16px", color: "#0070f3", fontWeight: "bold" }}>完了案件: {approvedMatches.length}件</div>
                            <div style={{ color: "#ffb400", fontWeight: "bold", fontSize: "14px" }}>★ 4.9 (24件)</div>
                        </div>
                    </div>
                    <div style={{ border: "1px solid #eee", padding: "25px", borderRadius: "20px", backgroundColor: "#fff" }}>
                        <p style={{ margin: 0, color: "#999", fontSize: "12px", fontWeight: "bold" }}>前週比成長率</p>
                        <h2 style={{ fontSize: "28px", margin: "5px 0", color: "#2e7d32", fontWeight: "bold" }}>+12.5% ↑</h2>
                    </div>
                </div>

                <div style={{ display: "grid", gridTemplateColumns: "1.2fr 0.8fr", gap: "30px" }}>
                    <section>
                        <h2 style={{ fontSize: "18px", marginBottom: "15px", color: "#444" }}>📍 博多エリア需要マップ</h2>
                        <div style={{ width: "100%", height: "300px", borderRadius: "24px", overflow: "hidden", border: "1px solid #eee" }}>
                            <Map defaultCenter={HAKATA_STATION} defaultZoom={14} disableDefaultUI={true}>
                                {userLocations.map(u => <Marker key={u.id} position={u.position} />)}
                            </Map>
                        </div>
                    </section>

                    <section>
                        <h2 style={{ fontSize: "17px", marginBottom: "15px", color: "#444" }}>進行中の案件</h2>
                        {approvedMatches.map((match: any) => (
                            <div key={match.id} style={{ padding: "20px", border: "1px solid #eee", borderRadius: "20px", background: "#fff", marginBottom: "15px" }}>
                                <div style={{ display: "flex", justifyContent: "space-between", marginBottom: "15px" }}>
                                    <span style={{ fontWeight: "bold" }}>{match.user?.name || match.name} 様</span>
                                    <span style={{ color: "#2e7d32", fontSize: "12px" }}>● 訪問中</span>
                                </div>
                                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "10px", marginBottom: "10px" }}>
                                    <button onClick={() => setShowSoapModal(true)} style={miniButtonStyle("#1a1a1a")}>📝 SOAP作成</button>
                                    <button onClick={() => setShowChart(true)} style={miniButtonStyle("#0070f3")}>📊 成果図解</button>
                                </div>
                                <button onClick={() => setShowSnsModal(true)} style={{ ...miniButtonStyle("#ff4b4b"), width: "100%", backgroundColor: "#fff5f5" }}>🚀 実績をSNSシェア</button>
                            </div>
                        ))}
                    </section>
                </div>

                {/* --- SOAPモーダル (既存機能) --- */}
                {showSoapModal && (
                    <div style={overlayStyle}>
                        <div style={modalStyle}>
                            <h2 style={{ fontSize: "18px", marginBottom: "15px" }}>AI記録アシスタント</h2>
                            <button onClick={runAiAnalysis} style={{ width: "100%", padding: "10px", backgroundColor: "#0070f3", color: "#fff", border: "none", borderRadius: "8px", marginBottom: "15px", cursor: "pointer" }}>
                                {isAiAnalyzing ? "チャットを解析中..." : "🪄 チャットから自動下書き"}
                            </button>
                            <div style={{ textAlign: "left" }}>
                                {Object.entries(soapForm).map(([key, val]) => (
                                    <div key={key} style={{ marginBottom: "8px" }}>
                                        <label style={{ fontSize: "11px", fontWeight: "bold" }}>{key.toUpperCase()}</label>
                                        <textarea value={val} onChange={(e) => setSoapForm({...soapForm, [key]: e.target.value})} style={textareaStyle} rows={2} />
                                    </div>
                                ))}
                            </div>
                            <button onClick={() => setShowSoapModal(false)} style={{ width: "100%", marginTop: "15px", padding: "12px", borderRadius: "10px", backgroundColor: "#1a1a1a", color: "#fff", border: "none", cursor: "pointer" }}>保存して共有</button>
                        </div>
                    </div>
                )}

                {/* --- 成果図解モーダル (既存機能) --- */}
                {showChart && (
                    <div style={overlayStyle}>
                        <div style={{ ...modalStyle, width: "480px" }}>
                            <h2 style={{ fontSize: "18px", marginBottom: "20px" }}>リハビリ成果レポート</h2>
                            <div style={{ display: "flex", justifyContent: "space-around", alignItems: "flex-end", height: "180px", background: "#f9f9f9", borderRadius: "20px", padding: "20px" }}>
                                <div style={{ width: "30%" }}>
                                    <div style={{ height: "60px", background: "#ccc", borderRadius: "8px" }}></div>
                                    <p style={{ fontSize: "11px" }}>初回: 10.2s</p>
                                </div>
                                <div style={{ width: "30%" }}>
                                    <div style={{ height: "130px", background: "#0070f3", borderRadius: "8px" }}></div>
                                    <p style={{ fontSize: "11px", fontWeight: "bold" }}>現在: 8.5s</p>
                                </div>
                            </div>
                            <button onClick={() => setShowChart(false)} style={{ width: "100%", marginTop: "20px", padding: "12px", borderRadius: "10px", border: "1px solid #ddd", cursor: "pointer" }}>閉じる</button>
                        </div>
                    </div>
                )}

                {/* --- SNSマルチシェア & 画像プレビューモーダル (新規) --- */}
                {showSnsModal && (
                    <div style={overlayStyle}>
                        <div style={{ ...modalStyle, width: "450px" }}>
                            <h2 style={{ fontSize: "18px", marginBottom: "20px" }}>SNS実績シェア</h2>
                            
                            {/* Instagram用画像プレビュー */}
                            <p style={{ fontSize: "12px", color: "#666", textAlign: "left", marginBottom: "8px" }}>📸 Instagram投稿用プレビュー（自動生成）</p>
                            <div id="insta-preview" style={{ width: "100%", aspectRatio: "1/1", background: "linear-gradient(135deg, #0070f3 0%, #00a3ff 100%)", borderRadius: "15px", display: "flex", flexDirection: "column", justifyContent: "center", alignItems: "center", color: "white", padding: "30px", textAlign: "center", boxShadow: "0 10px 20px rgba(0,112,243,0.2)", marginBottom: "20px" }}>
                                <span style={{ fontSize: "14px", fontWeight: "bold", opacity: 0.9 }}>REHABILITATION REPORT</span>
                                <h3 style={{ fontSize: "28px", margin: "15px 0", fontWeight: "900", lineHeight: 1.2 }}>歩行スピード<br/>17.5%向上！</h3>
                                <div style={{ height: "2px", width: "50px", background: "white", margin: "10px 0" }}></div>
                                <p style={{ fontSize: "14px" }}>博多エリアの訪問リハ実績</p>
                                <div style={{ marginTop: "20px", fontSize: "12px", background: "rgba(255,255,255,0.2)", padding: "5px 15px", borderRadius: "20px" }}>@pt_tada_hakata</div>
                            </div>

                            {/* 選択ボタン */}
                            <div style={{ textAlign: "left" }}>
                                <p style={{ fontSize: "12px", color: "#666", marginBottom: "10px" }}>シェア先を選択してください：</p>
                                <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "10px" }}>
                                    <button onClick={() => window.open(`https://twitter.com/intent/tweet?text=${encodeURIComponent("博多区での訪問リハ、1ヶ月で歩行スピードが17%向上しました！ #理学療法士 #博多")}`)} style={snsButtonStyle("#1a1a1a")}>
                                        𝕏 (Twitter)
                                    </button>
                                    <button onClick={() => alert("画像をカメラロールに保存しました。Instagramを開きます。")} style={snsButtonStyle("#E4405F")}>
                                        Instagram
                                    </button>
                                    <button onClick={() => window.open(`https://line.me/R/msg/text/?${encodeURIComponent("本日の成果報告です！歩行速度が17%改善しました。")}`)} style={snsButtonStyle("#06C755")}>
                                        LINE家族
                                    </button>
                                </div>
                            </div>

                            <button onClick={() => setShowSnsModal(false)} style={{ width: "100%", marginTop: "20px", padding: "12px", borderRadius: "12px", border: "1px solid #eee", backgroundColor: "white", cursor: "pointer" }}>キャンセル</button>
                        </div>
                    </div>
                )}

            </div>
        </APIProvider>
    );
}

// ヘルパースタイル
const miniButtonStyle = (color: string) => ({
    padding: "10px", backgroundColor: "white", color: color, border: `1px solid ${color}`, borderRadius: "10px", fontSize: "11px", fontWeight: "bold", cursor: "pointer"
} as const);

const snsButtonStyle = (bg: string) => ({
    padding: "12px 5px", backgroundColor: bg, color: "white", border: "none", borderRadius: "10px", fontSize: "11px", fontWeight: "bold", cursor: "pointer"
} as const);

const textareaStyle = { width: "100%", padding: "8px", borderRadius: "8px", border: "1px solid #ddd", fontSize: "13px", marginTop: "4px" } as const;

const overlayStyle = { position: "fixed" as const, top: 0, left: 0, width: "100%", height: "100%", backgroundColor: "rgba(0,0,0,0.6)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000, backdropFilter: "blur(5px)" };

const modalStyle = { backgroundColor: "white", padding: "30px", borderRadius: "28px", width: "420px", textAlign: "center" as const, boxShadow: "0 20px 40px rgba(0,0,0,0.3)" };